import { Injectable, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { Observable, tap, catchError, of } from 'rxjs';
import { environment } from '../../environments/environment';

export interface UsuarioLogueado {
  id: string;
  email: string;
  nombreCompleto: string;
  rol: string;
}

const STORAGE_KEY = 'probook_user';

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly apiUrl = `${environment.apiUrl}/auth`;
  private userSignal = signal<UsuarioLogueado | null>(null);

  currentUser = computed(() => this.userSignal());
  isLoggedIn = computed(() => this.userSignal() !== null);

  constructor(
    private http: HttpClient,
    private router: Router
  ) {
    this.restoreSession();
  }

  private restoreSession(): void {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      try {
        const user = JSON.parse(stored) as UsuarioLogueado;
        this.userSignal.set(user);
      } catch {
        localStorage.removeItem(STORAGE_KEY);
      }
    }
  }

  login(email: string, password?: string): Observable<UsuarioLogueado | null> {
    return this.http
      .post<UsuarioLogueado>(`${this.apiUrl}/login`, { email: email.trim() })
      .pipe(
        tap((user) => {
          this.userSignal.set(user);
          localStorage.setItem(STORAGE_KEY, JSON.stringify(user));
        }),
        catchError(() => of(null))
      );
  }

  logout(): void {
    this.userSignal.set(null);
    localStorage.removeItem(STORAGE_KEY);
    this.router.navigate(['/login']);
  }
}
